parameters.query:
=SELECT
  i.sku,
  i.item_name,
  i.price,
  COALESCE(i.stock, 0) AS stock,
  COALESCE(i.unit, 'pcs') AS unit,
  COALESCE(i.category_tag, 'general') AS category_tag
FROM public.inventory i
WHERE i.is_active = true
  AND COALESCE(i.stock, 0) > 0
  AND i.store_id = {{ Number($('Resolve Browse Context').first().json.store_id || 1) }}
  {{ (() => {
    const ti = $('Start').first().json.tool_input || {};
    const ep = String(ti.entry_point || 'browse_home').trim();
    const sku = String(ti.sku || '').trim().replace(/'/g, "''");
    const catKey = String(ti.category_key || '').trim().replace(/'/g, "''");
    const q = String(ti.user_query || '').trim().replace(/'/g, "''");
    if (sku) return `AND i.sku = '${sku}'`;
    if (ep === 'browse_search' && q) return `AND (i.item_name ILIKE '%${q}%' OR similarity(i.item_name, '${q}') > 0.1)`;
    if (ep === 'browse_category' && catKey) return `AND COALESCE(i.category_tag, 'general') = '${catKey}'`;
    return '';
  })() }}
ORDER BY
  {{ (() => {
    const ti = $('Start').first().json.tool_input || {};
    const ep = String(ti.entry_point || '').trim();
    const q = String(ti.user_query || '').trim().replace(/'/g, "''");
    if (ep === 'browse_search' && q) return `similarity(i.item_name, '${q}') DESC NULLS LAST,`;
    return '';
  })() }}
  i.item_name ASC
LIMIT 11
OFFSET {{ (() => {
  const ti = $('Start').first().json.tool_input || {};
  const ep = String(ti.entry_point || '').trim();
  const page = parseInt(ti.page || 0) || 0;
  return ['browse_category', 'browse_search'].includes(ep) ? page * 10 : 0;
})() }}

