const startRaw = (() => {
  try { return $('Start').first().json || {}; } catch { return {}; }
})();

let toolInput;
const rawTi = startRaw.tool_input;
if (rawTi && typeof rawTi === 'object') {
  toolInput = rawTi;
} else if (rawTi && typeof rawTi === 'string' && rawTi.startsWith('{')) {
  try { toolInput = JSON.parse(rawTi); } catch { toolInput = startRaw; }
} else {
  toolInput = startRaw;
}

const context = (() => {
  try { return $('Resolve Browse Context').first().json || {}; } catch { return {}; }
})();
const allRows = $input.all().map((entry) => entry && entry.json ? entry.json : null).filter(Boolean);
// 11 items = there are more; show 10 + "Show more"
const hasMore = allRows.length === 11;
const rows = hasMore ? allRows.slice(0, 10) : allRows;

const chatId = String(context.chat_id || toolInput.chat_id || '');
const storeName = String(context.store_name || 'your kirana store');
const cartItemCount = Number(context.cart_item_count || 0);
const cartTotal = Number(context.cart_total || 0);
const entryPoint = String(toolInput.entry_point || toolInput.user_query || 'browse').trim();
const categoryKey = String(toolInput.category_key || '').trim();
const focusSku = String(toolInput.sku || toolInput.focus_sku || '').trim();
const userQuery = String(toolInput.user_query || '').trim();
const page = parseInt(toolInput.page || 0) || 0;

let recentSkus = [];
try {
  const parsed = JSON.parse(context.recent_skus_json || '[]');
  recentSkus = Array.isArray(parsed) ? parsed.map(String) : [];
} catch {}

const shortTitle = (value) => {
  const text = String(value || '').trim().replace(/\s+/g, ' ');
  return text.length > 24 ? text.slice(0, 21) + '...' : text;
};

const categoryMeta = {
  daily_essentials: { title: 'Daily Essentials', description: 'Milk, bread, eggs & staples' },
  vegetables_fruits: { title: 'Vegetables & Fruits', description: 'Fresh produce' },
  staples: { title: 'Grains & Oils', description: 'Rice, atta, dal, oil' },
  snacks_drinks: { title: 'Snacks & Drinks', description: 'Biscuits, chips, beverages' },
  general: { title: 'More Items', description: 'Other items in the store' },
};

const cartRows = [];
if (cartItemCount > 0) {
  cartRows.push({ id: 'checkout', title: '✓ Checkout', description: 'Cart total ₹' + cartTotal.toFixed(0) });
}
cartRows.push({ id: 'view_cart', title: '🛒 View Cart', description: cartItemCount > 0 ? cartItemCount + ' items in cart' : 'See your current cart' });

// Search prompt: user tapped 🔍 Search — send prompt and set browse_context
if (entryPoint === 'browse_search_prompt') {
  return [{ json: {
    chat_id: chatId, customer_ui_state: 'BROWSE_SEARCH_PROMPT', message_type: 'button',
    body_text: '🔍 Search items\n\nType the name of what you\'re looking for and send it.\nExample: milk, rice, onion',
    buttons: [
      { id: 'browse', title: '← Browse Categories' },
      { id: 'view_cart', title: '🛒 Cart' },
    ],
    browse_context_to_set: 'awaiting_search',
  } }];
}

if (!rows.length && entryPoint === 'browse_search') {
  return [{ json: {
    chat_id: chatId, customer_ui_state: 'BROWSE_HOME', message_type: 'button',
    body_text: 'No results found for "' + userQuery + '"\n\nTry a different search term or browse by category.',
    buttons: [{ id: 'browse', title: '← Browse Categories' }, { id: 'view_cart', title: '🛒 Cart' }],
    browse_context_to_set: null,
  } }];
}

if (!rows.length) {
  return [{ json: {
    chat_id: chatId, customer_ui_state: 'BROWSE_HOME', message_type: 'button',
    body_text: 'Shop items\n\nWe are still setting up items for ' + storeName + '.',
    buttons: [{ id: 'view_cart', title: '🛒 Cart' }, { id: 'get_promos', title: 'Offers' }],
    browse_context_to_set: null,
  } }];
}

// Search results
if (entryPoint === 'browse_search') {
  const searchRows = rows.map((row) => ({
    id: 'browse_item__' + String(row.sku || ''),
    title: shortTitle(row.item_name),
    description: '₹' + Number(row.price || 0).toFixed(0) + ' per ' + (row.unit || 'pcs'),
  }));
  if (hasMore) {
    searchRows.push({ id: 'browse_search_more__' + (page + 1), title: '→ Show more results', description: 'Load next page' });
  }
  return [{ json: {
    chat_id: chatId, customer_ui_state: 'BROWSE_SEARCH', message_type: 'list',
    body_text: 'Search results for "' + userQuery + '"' + (page > 0 ? ' (page ' + (page + 1) + ')' : '') + '\n\nTap an item to choose quantity.',
    list_sections: [
      { title: 'Results', rows: searchRows },
      { title: 'Actions', rows: [{ id: 'browse', title: '← Browse Categories', description: 'Back to categories' }, ...cartRows] },
    ],
    browse_context_to_set: null,
  } }];
}

// Custom qty prompt
if (entryPoint === 'browse_qty_custom' && focusSku) {
  const row = rows.find((r) => String(r.sku || '') === focusSku) || rows[0];
  if (row) {
    return [{ json: {
      chat_id: chatId, customer_ui_state: 'ITEM_QUANTITY_PICKER', message_type: 'button',
      body_text: 'Custom quantity\n\nSend a message like "6 ' + row.item_name + '" to add it to your cart.\n\n' + row.item_name + ' • ₹' + Number(row.price || 0).toFixed(0) + ' per ' + (row.unit || 'pcs'),
      buttons: [{ id: 'browse', title: '← Browse' }, { id: 'view_cart', title: '🛒 Cart' }],
      browse_context_to_set: 'awaiting_qty__' + focusSku,
    } }];
  }
}

// Item quantity picker
if (focusSku) {
  const row = rows.find((r) => String(r.sku || '') === focusSku) || rows[0];
  if (row) {
    const catKey = String(row.category_tag || 'general');
    return [{ json: {
      chat_id: chatId, customer_ui_state: 'ITEM_QUANTITY_PICKER', message_type: 'list',
      body_text: 'Choose quantity\n\n' + row.item_name + '\nPrice: ₹' + Number(row.price || 0).toFixed(0) + ' per ' + (row.unit || 'pcs') + '\nIn stock: ' + Number(row.stock || 0),
      list_sections: [
        {
          title: 'Pick quantity',
          rows: [1, 2, 3, 4, 5].map((qty) => ({
            id: 'set_qty__' + row.sku + '__' + qty,
            title: 'Add ' + qty + ' ' + (row.unit || 'pcs'),
            description: '₹' + (Number(row.price || 0) * qty).toFixed(0) + ' total',
          })).concat([{ id: 'set_qty_custom__' + row.sku, title: '✏️ Custom quantity', description: 'Type a custom amount' }]),
        },
        {
          title: 'More',
          rows: [
            { id: 'browse_category__' + catKey, title: '← Back to category', description: (categoryMeta[catKey] || categoryMeta.general).title },
            ...cartRows,
          ],
        },
      ],
      browse_context_to_set: null,
    } }];
  }
}

// Category list (paginated)
if (entryPoint === 'browse_category' && categoryKey) {
  const meta = categoryMeta[categoryKey] || { title: 'Items', description: 'Pick an item' };
  const itemRows = rows.map((row) => ({
    id: 'browse_item__' + row.sku,
    title: shortTitle(row.item_name),
    description: '₹' + Number(row.price || 0).toFixed(0) + ' per ' + (row.unit || 'pcs'),
  }));
  if (hasMore) {
    itemRows.push({ id: 'browse_more__' + categoryKey + '__' + (page + 1), title: '→ Show more', description: 'Next 10 items' });
  }
  return [{ json: {
    chat_id: chatId, customer_ui_state: 'BROWSE_CATEGORY', message_type: 'list',
    body_text: meta.title + (page > 0 ? ' (page ' + (page + 1) + ')' : '') + '\n\nTap an item to choose quantity.',
    list_sections: [
      { title: meta.title, rows: itemRows },
      { title: 'More', rows: [{ id: 'browse', title: '← All Categories', description: 'Back to home' }, ...cartRows] },
    ],
    browse_context_to_set: null,
  } }];
}

// Browse home - group by category_tag from DB
const rowsByCategory = new Map();
for (const row of rows) {
  if (!row || !row.sku) continue;
  const key = String(row.category_tag || 'general');
  if (!rowsByCategory.has(key)) rowsByCategory.set(key, []);
  rowsByCategory.get(key).push(row);
}

const homeRows = [];
for (const [key, catRows] of rowsByCategory) {
  const meta = categoryMeta[key] || { title: key, description: catRows.length + ' items' };
  homeRows.push({
    id: 'browse_category__' + key,
    title: meta.title,
    description: meta.description + ' • ' + catRows.length + ' items',
  });
}
homeRows.push({ id: 'browse_search', title: '🔍 Search items', description: 'Find any item by name' });

const listSections = [];
if (recentSkus.length > 0) {
  const recentRows = recentSkus
    .map((sku) => rows.find((r) => String(r.sku || '') === sku))
    .filter(Boolean)
    .map((row) => ({ id: 'browse_item__' + row.sku, title: shortTitle(row.item_name), description: '₹' + Number(row.price || 0).toFixed(0) + ' • Added recently' }));
  if (recentRows.length > 0) listSections.push({ title: 'Recently added', rows: recentRows });
}
listSections.push({ title: 'Browse categories', rows: homeRows });
listSections.push({ title: 'Cart', rows: cartRows });

return [{ json: {
  chat_id: chatId, customer_ui_state: 'BROWSE_HOME', message_type: 'list',
  body_text: 'Shop at ' + storeName + '\n\nWhat would you like today?' + (cartItemCount > 0 ? '\nCart: ' + cartItemCount + ' items • ₹' + cartTotal.toFixed(0) : ''),
  list_sections: listSections,
  browse_context_to_set: null,
} }];

const payload = $('Format Browse Response').first().json;
const { browse_context_to_set, ...clean } = payload;
return [{ json: clean }];

